import 'twin.macro'
import { graphql, HeadFC } from 'gatsby'
import * as React from 'react'
import Layout from '../components/layout'
import Seo from '../components/seo'
import SyntaxHighlightStyles from '../styles/syntax-highlight'

export const pageQuery = graphql`
  query ($id: String) {
    markdownRemark(id: { eq: $id }) {
      html
      fields {
        slug
      }
      excerpt(pruneLength: 100, format: PLAIN)
      frontmatter {
        title
        subtitle
        featuredImage {
          publicURL
        }
      }
    }
  }
`

interface PatternTemplateProps {
  data: {
    markdownRemark: {
      html: string
      fields: { slug: string }
      excerpt: string
      frontmatter: {
        title: string
        subtitle: string
        featuredImage: {
          publicURL: string
        }
      }
    }
  }
}

const PatternTemplate: React.FC<PatternTemplateProps> = ({
  data: {
    markdownRemark: {
      html,
      fields,
      frontmatter: { title, subtitle },
    },
  },
}) => (
  <Layout>
    <SyntaxHighlightStyles />
    <header tw="pt-20 mb-20 relative">
      <h1 tw="mb-4 bg-clip-text bg-gradient-to-r break-words font-extrabold from-pink-500 text-[2.75rem] md:text-[5rem] text-center text-transparent to-blue-500 tracking-tighter">
        {title}
      </h1>
      <p tw="text-gray-900 mb-8 text-center text-xl">{subtitle}</p>

      <a
        href={`https://docs.google.com/forms/d/e/1FAIpQLScQPXWUlnKvkAhf7JJMENcPywlPKMmIFCYonxEByqKNJ3lu2g/viewform?usp=pp_url&entry.2111705104=${fields?.slug}`}
        target="_blank"
        rel="noreferrer"
        tw="absolute block right-0 bottom-[-2rem] md:bottom-0 text-sm font-bold"
      >
        📮 피드백 보내기
      </a>
    </header>

    <div className="markdown" dangerouslySetInnerHTML={{ __html: html }} />
  </Layout>
)

/* eslint-disable react/prop-types */
export const Head: HeadFC<PatternTemplateProps['data']> = ({
  data: {
    markdownRemark: {
      excerpt,
      fields: { slug },
      frontmatter: { title, subtitle, featuredImage },
    },
  },
}) => (
  <Seo
    pathname={slug}
    title={title}
    description={`${subtitle} - ${excerpt}`.slice(0, 200)}
    image={featuredImage.publicURL}
  />
)
/* eslint-enable react/prop-types */

export default PatternTemplate
